import{_ as e,o as a,c as o,ae as r}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"Track B: Merchant Hub & Registry UI","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/tracks/track_b_merchant_hub.md","filePath":"docs/plans/tracks/track_b_merchant_hub.md"}'),n={name:"docs/plans/tracks/track_b_merchant_hub.md"};function i(s,t,c,l,h,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="track-b-merchant-hub-registry-ui" tabindex="-1">Track B: Merchant Hub &amp; Registry UI <a class="header-anchor" href="#track-b-merchant-hub-registry-ui" aria-label="Permalink to &quot;Track B: Merchant Hub &amp; Registry UI&quot;">​</a></h1><p><strong>Branch Name:</strong> <code>feat/merchant-hub-ui</code><strong>Base Branch:</strong> <code>base-integration</code> (Consolidated)</p><h2 id="_1-objective" tabindex="-1">1. Objective <a class="header-anchor" href="#_1-objective" aria-label="Permalink to &quot;1. Objective&quot;">​</a></h2><p>To transform the Hub into a &quot;Commercial Terminal&quot; that visualizes the full range of the Agent&#39;s financial power. It must support listing products, accepting various payment strategies (including Starpay Cards), and displaying the complex status of cross-chain operations.</p><h2 id="_2-core-components" tabindex="-1">2. Core Components <a class="header-anchor" href="#_2-core-components" aria-label="Permalink to &quot;2. Core Components&quot;">​</a></h2><h3 id="_2-1-the-merchant-registry-on-chain" tabindex="-1">2.1. The Merchant Registry (On-Chain) <a class="header-anchor" href="#_2-1-the-merchant-registry-on-chain" aria-label="Permalink to &quot;2.1. The Merchant Registry (On-Chain)&quot;">​</a></h3><p>Enhanced to support sophisticated service listings.</p><ul><li><strong>Path:</strong> <code>onchain/programs/xb77_registry/</code></li><li><strong>New Data:</strong> Add <code>supported_methods</code> bitmask to Merchant accounts (e.g., accepts <code>PRIVACY_CASH | STARPAY_CARD | SILENTSWAP_BRIDGED</code>).</li><li><strong>Products:</strong> Define &quot;Virtual Goods&quot; (e.g., &quot;AWS Credits&quot;, &quot;Confidential Compute&quot;) that justify using Starpay or ShadowWire.</li></ul><h3 id="_2-2-hub-ui-the-agent-dashboard-client" tabindex="-1">2.2. Hub UI: The Agent Dashboard (Client) <a class="header-anchor" href="#_2-2-hub-ui-the-agent-dashboard-client" aria-label="Permalink to &quot;2.2. Hub UI: The Agent Dashboard (Client)&quot;">​</a></h3><ul><li><strong>Strategy Selector:</strong> A UI component that lets the user configure the Agent&#39;s &quot;CFO Settings&quot; (e.g., &quot;Always use Starpay for amounts &lt; $50&quot;).</li><li><strong>Card Viewer:</strong> A secure component to display Starpay Virtual Card details (PAN, CVV) generated by Track A.</li><li><strong>Cross-Chain Monitor:</strong> A status panel showing SilentSwap bridge operations (&quot;Moving to Base... 40%&quot;).</li></ul><h3 id="_2-3-hub-ui-the-merchant-dashboard-vendor" tabindex="-1">2.3. Hub UI: The Merchant Dashboard (Vendor) <a class="header-anchor" href="#_2-3-hub-ui-the-merchant-dashboard-vendor" aria-label="Permalink to &quot;2.3. Hub UI: The Merchant Dashboard (Vendor)&quot;">​</a></h3><ul><li><strong>Sales Feed:</strong> Real-time list of incoming payments.</li><li><strong>Multi-Rail Recognition:</strong> Visual distinction between a &quot;Privacy Cash&quot; payment and a &quot;Starpay Card&quot; settlement.</li><li><strong>Invoice Generator:</strong> Button to manually issue a <strong>Compressed Receipt</strong> (Light Protocol) if one wasn&#39;t auto-generated.</li></ul><h2 id="_3-integration-points" tabindex="-1">3. Integration Points <a class="header-anchor" href="#_3-integration-points" aria-label="Permalink to &quot;3. Integration Points&quot;">​</a></h2><h3 id="input-from-track-a-agent-core" tabindex="-1">Input from Track A (Agent Core) <a class="header-anchor" href="#input-from-track-a-agent-core" aria-label="Permalink to &quot;Input from Track A (Agent Core)&quot;">​</a></h3><ul><li>The Hub uses the <code>AutonomousCFO</code> class from the SDK to execute actions.</li><li>It subscribes to SDK events to update the UI (e.g., &quot;Card Created&quot;, &quot;Swap Initiated&quot;).</li></ul><h3 id="input-from-track-c-infra-listener" tabindex="-1">Input from Track C (Infra Listener) <a class="header-anchor" href="#input-from-track-c-infra-listener" aria-label="Permalink to &quot;Input from Track C (Infra Listener)&quot;">​</a></h3><ul><li><strong>Data Feeds:</strong> The Hub does <em>not</em> query the chain directly for complex history. It queries the <strong>MCP API</strong> (Track C) to get the aggregated history of all rails (ShadowWire + Starpay + SilentSwap).</li><li><strong>Real-Time:</strong> WebSockets from Track C update the Sales Feed.</li></ul><h2 id="_4-execution-plan" tabindex="-1">4. Execution Plan <a class="header-anchor" href="#_4-execution-plan" aria-label="Permalink to &quot;4. Execution Plan&quot;">​</a></h2><ol><li><strong>Registry Upgrade:</strong> Update Rust program to support payment methods metadata. (DONE)</li><li><strong>Product UI:</strong> Build the &quot;Marketplace&quot; view. (DONE - Static Mock)</li><li><strong>Checkout Flow:</strong> Connect the &quot;Buy&quot; button to <code>agent.pay(strategy)</code>. (DONE - Tool Call Dispatcher)</li><li><strong>Starpay UI:</strong> Build the Virtual Card display component. (PENDING - Needs Track A Adapter)</li><li><strong>History Integration:</strong> Connect the Activity Feed to the Track C API. (PENDING - Needs Track C Webhooks)</li></ol><h2 id="_5-next-steps-after-merge" tabindex="-1">5. Next Steps (After Merge) <a class="header-anchor" href="#_5-next-steps-after-merge" aria-label="Permalink to &quot;5. Next Steps (After Merge)&quot;">​</a></h2><ul><li><strong>On-Chain Catalogs:</strong> Implement <code>AddProduct</code> instruction in <code>xb77_registry</code> to move products from static JSON in the Hub to on-chain state.</li><li><strong>Agent Handshake:</strong> Verify the <code>agent.pay</code> tool signature in the Hub to prevent unauthorized tool dispatch from the UI.</li><li><strong>Live Stats:</strong> Connect the &quot;Total Sales&quot; counter to the <code>xb77_receipts</code> program state.</li></ul>',21)])])}const p=e(n,[["render",i]]);export{g as __pageData,p as default};
